arguments.file_text:
@page "/settings"
@rendermode InteractiveServer
@using sv_ada79363690c48aea217a62f1cc25cca.Services

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        @foreach (var section in _sections)
        {
            <button class="sidebar-item @(section == _activeSection ? "active" : "")"
                    @onclick="() => _activeSection = section">
                <span class="sidebar-icon">@GetIcon(section)</span>
                @section
            </button>
        }
    </nav>

    <main class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </main>
</div>

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 3.5rem);
    gap: 0;
}

.settings-sidebar {
    width: 240px;
    min-width: 240px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
    display: flex;
    flex-direction: column;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    border: none;
    background: none;
    text-align: left;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
    width: 100%;
}

.sidebar-item:hover {
    background: #e9ecef;
    color: #212529;
}

.sidebar-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-right: 3px solid #0d6efd;
}

.sidebar-icon {
    font-size: 1.1rem;
    width: 1.5rem;
    text-align: center;
}

.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    max-width: 800px;
}

::deep .section-header {
    margin-bottom: 1.5rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid #dee2e6;
}

::deep .section-header h3 {
    margin: 0;
    font-weight: 600;
}

::deep .section-header p {
    margin: 0.25rem 0 0;
    color: #6c757d;
    font-size: 0.9rem;
}

::deep .toast-message {
    position: fixed;
    top: 1rem;
    right: 1rem;
    padding: 0.75rem 1.25rem;
    border-radius: 0.375rem;
    color: #fff;
    font-weight: 500;
    z-index: 1050;
    animation: toast-slide 0.3s ease-out;
}

::deep .toast-success {
    background: #198754;
}

::deep .toast-error {
    background: #dc3545;
}

@keyframes toast-slide {
    from { transform: translateX(100%); opacity: 0; }
    to { transform: translateX(0); opacity: 1; }
}

@using sv_ada79363690c48aea217a62f1cc25cca.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h3>Profile</h3>
    <p>Manage your personal information</p>
</div>

@if (_loading)
{
    <p class="text-muted">Loading profile...</p>
}
else
{
    <div class="profile-form">
        <div class="avatar-area mb-4">
            <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
            <div class="avatar-url-display">
                <label class="form-label fw-semibold">Avatar URL</label>
                <input type="url" class="form-control" value="@_avatarUrl" disabled />
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Display Name</label>
            <input type="text" class="form-control" @bind="_displayName" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Email</label>
            <input type="email" class="form-control" @bind="_email" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="3" @bind="_bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving..." : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                Discard Changes
            </button>
        </div>
    </div>
}

@if (_toastMessage is not null)
{
    <div class="toast-message toast-success">@_toastMessage</div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    // Saved state for discard
    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
    }

    private async Task ShowToast(string message)
    {
        _toastMessage = message;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

.avatar-area {
    display: flex;
    align-items: center;
    gap: 1.5rem;
}

.avatar-preview {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
    flex-shrink: 0;
}

.avatar-url-display {
    flex: 1;
}

@using sv_ada79363690c48aea217a62f1cc25cca.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h3>Notifications</h3>
    <p>Control how and when you receive notifications</p>
</div>

@if (_loading)
{
    <p class="text-muted">Loading preferences...</p>
}
else
{
    <div class="mb-4">
        <h6 class="fw-semibold mb-3">General</h6>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
