@using sv_ada79363690c48aea217a62f1cc25cca.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h3>Appearance</h3>
    <p>Customize how the application looks and feels</p>
</div>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings...</p>
}
else
{
    <div class="row">
        <div class="col-md-7">
            <!-- Theme -->
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Theme</h6>
                @foreach (var theme in _themes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="theme"
                               id="theme-@theme" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="theme-@theme">@theme</label>
                    </div>
                }
            </div>

            <!-- Font Size -->
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Font Size</h6>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="fs-@size" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="fs-@size">@size</label>
                    </div>
                }
            </div>

            <!-- Language -->
            <div class="mb-4">
                <h6 class="fw-semibold mb-2">Language</h6>
                <select class="form-select" style="max-width: 250px"
                        @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           @bind="_compactMode" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving..." : "Save")
            </button>
        </div>

        <!-- Live Preview -->
        <div class="col-md-5">
            <div class="preview-area @GetPreviewThemeClass()" style="@GetPreviewFontStyle()">
                <h6 class="fw-semibold mb-2">Preview</h6>
                <div class="preview-card @(_compactMode ? "compact" : "")">
                    <div class="preview-header">Dashboard</div>
                    <div class="preview-body">
                        <p>This is how your content will look with the selected settings.</p>
                        <div class="preview-item">📊 Analytics Overview</div>
                        <div class="preview-item">📋 Recent Activity</div>
                        <div class="preview-item">⚙️ Quick Settings</div>
                    </div>
                    <div class="preview-footer">
                        Theme: @_theme · Font: @_fontSize · Lang: @_language
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@if (_toastMessage is not null)
{
    <div class="toast-message toast-success">@_toastMessage</div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        await SettingsService.SaveAppearanceAsync(
            new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _saving = false;
        await ShowToast("Appearance settings saved!");
    }

    private string GetPreviewThemeClass() => _theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string GetPreviewFontStyle() => _fontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    private async Task ShowToast(string message)
    {
        _toastMessage = message;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

