.preview-area {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1rem;
    transition: all 0.2s;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
}

.preview-dark .preview-card {
    background: #2a2a3d;
    border-color: #3a3a50;
}

.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    overflow: hidden;
    transition: all 0.2s;
}

.preview-card.compact .preview-body,
.preview-card.compact .preview-header,
.preview-card.compact .preview-footer {
    padding-top: 0.25rem;
    padding-bottom: 0.25rem;
}

.preview-card.compact .preview-item {
    padding: 0.2rem 0;
}

.preview-header {
    padding: 0.5rem 0.75rem;
    font-weight: 600;
    border-bottom: 1px solid inherit;
}

.preview-light .preview-header {
    background: #f8f9fa;
}

.preview-dark .preview-header {
    background: #33334d;
}

.preview-body {
    padding: 0.75rem;
}

.preview-body p {
    margin-bottom: 0.5rem;
}

.preview-item {
    padding: 0.35rem 0;
}

.preview-footer {
    padding: 0.4rem 0.75rem;
    font-size: 0.75em;
    opacity: 0.7;
    border-top: 1px solid inherit;
}

.preview-light .preview-footer {
    background: #f8f9fa;
}

.preview-dark .preview-footer {
    background: #33334d;
}

